import{_ as e,o as i,c as r,a2 as o}from"./chunks/framework.Wufm-cgV.js";const b=JSON.parse('{"title":"常见问题","description":"常见问题解答","frontmatter":{"title":"常见问题","description":"常见问题解答"},"headers":[],"relativePath":"zh/guide/faq.md","filePath":"zh/guide/faq.md"}'),t={name:"zh/guide/faq.md"};function l(h,a,s,d,n,c){return i(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="通用" tabindex="-1">通用 <a class="header-anchor" href="#通用" aria-label="Permalink to &quot;通用&quot;">​</a></h2><h3 id="webrouter-是什么" tabindex="-1">WebRouter 是什么？ <a class="header-anchor" href="#webrouter-是什么" aria-label="Permalink to &quot;WebRouter 是什么？&quot;">​</a></h3><p>WebRouter 是开源 AI API 网关，统一管理多个大模型 Provider。提供健康监控、智能路由、成本追踪、团队管理和隐私脱敏。</p><h3 id="适合谁用" tabindex="-1">适合谁用？ <a class="header-anchor" href="#适合谁用" aria-label="Permalink to &quot;适合谁用？&quot;">​</a></h3><ul><li>希望一把 API Key 管理多个 AI Provider 的开发者</li><li>需要成本可视化和额度管理的工程团队</li><li>需要统一管理公司 AI API 使用量的企业</li></ul><h2 id="许可证" tabindex="-1">许可证 <a class="header-anchor" href="#许可证" aria-label="Permalink to &quot;许可证&quot;">​</a></h2><h3 id="webrouter-用什么许可证" tabindex="-1">WebRouter 用什么许可证？ <a class="header-anchor" href="#webrouter-用什么许可证" aria-label="Permalink to &quot;WebRouter 用什么许可证？&quot;">​</a></h3><p>社区版（CE）使用 <strong>Business Source License 1.1 (BSL 1.1)</strong>。2029 年 6 月 1 日自动转为 Apache License 2.0。</p><h3 id="免费使用吗" tabindex="-1">免费使用吗？ <a class="header-anchor" href="#免费使用吗" aria-label="Permalink to &quot;免费使用吗？&quot;">​</a></h3><p>是的。CE 免费用于个人使用、企业内部生产部署、学习研究。</p><h3 id="bsl-1-1-禁止什么" tabindex="-1">BSL 1.1 禁止什么？ <a class="header-anchor" href="#bsl-1-1-禁止什么" aria-label="Permalink to &quot;BSL 1.1 禁止什么？&quot;">​</a></h3><ul><li>将 WebRouter 或衍生品作为商业产品售卖</li><li>提供付费托管服务</li><li>OEM 嵌入闭源产品转售</li></ul><h3 id="企业版呢" tabindex="-1">企业版呢？ <a class="header-anchor" href="#企业版呢" aria-label="Permalink to &quot;企业版呢？&quot;">​</a></h3><p>企业版（EE）使用专有 EULA，包含 SSO、自定义审计日志、自定义统计指标、集群部署、商业支持等。</p><h2 id="技术" tabindex="-1">技术 <a class="header-anchor" href="#技术" aria-label="Permalink to &quot;技术&quot;">​</a></h2><h3 id="支持什么数据库" tabindex="-1">支持什么数据库？ <a class="header-anchor" href="#支持什么数据库" aria-label="Permalink to &quot;支持什么数据库？&quot;">​</a></h3><p>SQLite（默认零配置），也支持 MySQL 和 PostgreSQL。</p><h3 id="支持流式响应吗" tabindex="-1">支持流式响应吗？ <a class="header-anchor" href="#支持流式响应吗" aria-label="Permalink to &quot;支持流式响应吗？&quot;">​</a></h3><p>支持。wr-proxy 支持 SSE 流式传输。</p><h3 id="支持什么-provider-类型" tabindex="-1">支持什么 Provider 类型？ <a class="header-anchor" href="#支持什么-provider-类型" aria-label="Permalink to &quot;支持什么 Provider 类型？&quot;">​</a></h3><p><code>direct</code>、<code>aggregate</code>、<code>litellm</code>、<code>custom</code>——任何 OpenAI 兼容的 Provider。</p><h2 id="故障排除" tabindex="-1">故障排除 <a class="header-anchor" href="#故障排除" aria-label="Permalink to &quot;故障排除&quot;">​</a></h2><h3 id="健康检测显示不可用" tabindex="-1">健康检测显示不可用 <a class="header-anchor" href="#健康检测显示不可用" aria-label="Permalink to &quot;健康检测显示不可用&quot;">​</a></h3><ol><li>验证 Base URL 是否正确</li><li>检查 API Key 是否有效</li><li>确认服务器到 Provider 的网络连通性</li><li>查看 Provider 状态页是否有故障</li></ol><h3 id="token-不工作" tabindex="-1">Token 不工作 <a class="header-anchor" href="#token-不工作" aria-label="Permalink to &quot;Token 不工作&quot;">​</a></h3><ol><li>检查 Token 是否启用</li><li>确认配额是否耗尽</li><li>确保请求的模型在 Token 白名单中</li><li>检查速率限制</li></ol><h3 id="如何重置管理员密码" tabindex="-1">如何重置管理员密码？ <a class="header-anchor" href="#如何重置管理员密码" aria-label="Permalink to &quot;如何重置管理员密码？&quot;">​</a></h3><p>设置环境变量后重启：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">WEBROUTER_ADMIN_PASSWORD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">newpassword</span></span></code></pre></div>',30)])])}const p=e(t,[["render",l]]);export{b as __pageData,p as default};
